  // ===== Session Compass (Daniela's Compass) Routes =====
  // Provides tutoring session context: elapsed time, topics, parking lot
  // Behind COMPASS_ENABLED feature flag
  
  // Get Compass context for a conversation
  app.get('/api/compass/:conversationId', isAuthenticated, async (req: any, res) => {
    if (!COMPASS_ENABLED) {
      return res.status(404).json({ message: "Compass feature not enabled" });
    }
    
    try {
      const userId = getRequestUserId(req);
      const { conversationId } = req.params;
      
      // Verify user owns this conversation
      const conversation = await storage.getConversation(conversationId);
      if (!conversation || conversation.userId !== userId) {
        return res.status(404).json({ message: "Conversation not found" });
      }
      
      const context = await sessionCompassService.getCompassContext(conversationId);
      if (!context) {
        return res.json({ 
          active: false,
          message: "No active Compass session for this conversation" 
        });
      }
      
      res.json({
        active: true,
        ...context
      });
    } catch (error: any) {
      console.error("Error fetching Compass context:", error);
      res.status(500).json({ message: "Failed to fetch Compass context" });
    }
  });
  
  // Add item to parking lot
  app.post('/api/compass/:conversationId/parking', isAuthenticated, async (req: any, res) => {
    if (!COMPASS_ENABLED) {
      return res.status(404).json({ message: "Compass feature not enabled" });
    }
    
    try {
      const userId = getRequestUserId(req);
      const { conversationId } = req.params;
      const { content, source } = req.body;
      
      if (!content || typeof content !== 'string') {
        return res.status(400).json({ message: "Content is required" });
      }
      
      // Verify user owns this conversation
      const conversation = await storage.getConversation(conversationId);
      if (!conversation || conversation.userId !== userId) {
        return res.status(404).json({ message: "Conversation not found" });
      }
      
      // Find active session
      const session = await sessionCompassService.getActiveSession(conversationId);
      if (!session) {
        return res.status(404).json({ message: "No active session for this conversation" });
      }
      
      const parkingItem = await sessionCompassService.addParkingItem(
        session.id,
        content,
        source || 'tutor'
      );
      
      res.json({ success: true, parkingItem });
    } catch (error: any) {
      console.error("Error adding parking item:", error);
      res.status(500).json({ message: "Failed to add parking item" });
    }
  });
  
  // Update topic status
  app.patch('/api/compass/topics/:topicId', isAuthenticated, async (req: any, res) => {
    if (!COMPASS_ENABLED) {
      return res.status(404).json({ message: "Compass feature not enabled" });
    }
    
    try {
      const userId = getRequestUserId(req);
      const { topicId } = req.params;
      const { status } = req.body;
      
      const validStatuses = ['pending', 'in_progress', 'covered', 'partial', 'deferred', 'skipped'];
      if (!status || !validStatuses.includes(status)) {
        return res.status(400).json({ 
          message: `Invalid status. Must be one of: ${validStatuses.join(', ')}` 
        });
      }
      
      // Verify ownership through the session
      const topic = await sessionCompassService.getTopicById(topicId);
      if (!topic) {
        return res.status(404).json({ message: "Topic not found" });
      }
      
      // Get the session and verify the user owns the conversation
      const session = await sessionCompassService.getSessionById(topic.sessionId);
      if (!session) {
        return res.status(404).json({ message: "Session not found" });
      }
      
      const conversation = await storage.getConversation(session.conversationId);
      if (!conversation || conversation.userId !== userId) {
        return res.status(403).json({ message: "Not authorized" });
      }
      
      const updated = await sessionCompassService.updateTopicStatus(topicId, status);
      res.json({ success: true, topic: updated });
    } catch (error: any) {
      console.error("Error updating topic status:", error);
      res.status(500).json({ message: "Failed to update topic status" });
    }
  });

  // ===== Architect's Voice Routes =====
  // Enables the AI architect (Claude) to inject notes into active voice sessions
  
  // Inject a note into an active voice session
  // SECURITY: Requires architect secret (allows Claude to inject without user session)
  // The secret protects against unauthorized access from other AI agents
  app.post('/api/architect/inject', async (req: any, res) => {
    try {
      // SECURITY: Validate architect secret (this is the primary security gate)
      const architectSecret = req.headers['x-architect-secret'] as string;
      if (!validateArchitectSecret(architectSecret)) {
        return res.status(401).json({ message: "Unauthorized" });
      }
      
      const { conversationId, content } = req.body;
      
      if (!conversationId || !content) {
        return res.status(400).json({ message: "conversationId and content are required" });
      }
      
      // Verify conversation exists (architect has special access to any conversation)
      const [conversation] = await getSharedDb().select().from(conversations).where(eq(conversations.id, conversationId));
      if (!conversation) {
        return res.status(404).json({ message: "Conversation not found" });
      }
      
      // Inject the note (async - persisted to database)
      const note = await architectVoiceService.injectNote(conversationId, content);
      
      console.log(`[Architect Voice] Note injected into conversation ${conversationId}`);
      
      // REAL-TIME TRIGGER: If there's an active voice session, trigger Daniela immediately
      // This enables true 3-way collaboration without waiting for the user to speak
      const orchestrator = getStreamingVoiceOrchestrator();
      const activeSession = orchestrator.findSessionByConversationId(conversationId);
      let triggeredImmediateResponse = false;
      
      if (activeSession) {
        console.log(`[Architect Voice] 🏗️ Found active session - triggering immediate Daniela response`);
        // Don't await - let the response stream in the background
        // Pass noteId so it can be marked as delivered after successful response
        orchestrator.triggerArchitectResponse(activeSession, content, note.id).catch(err => {
          console.error(`[Architect Voice] Failed to trigger response:`, err.message);
        });
        triggeredImmediateResponse = true;
      } else {
        console.log(`[Architect Voice] No active voice session - note stored for next turn`);
      }
      
      res.json({ 
        success: true, 
        note: {
          id: note.id,
          content: note.content,
          timestamp: note.timestamp
        },
        immediateResponse: triggeredImmediateResponse,
        message: triggeredImmediateResponse 
          ? 'Note delivered - Daniela is responding now!' 
          : 'Note stored - will be delivered when user speaks next'
      });
    } catch (error: any) {
      console.error("Error injecting architect note:", error);
      res.status(500).json({ message: "Failed to inject note" });
    }
  });
  
