  // ===== Lesson Prerequisites (Class Context Only) =====

  // Check if a class lesson's prerequisites are met
  // This only applies to class-based learning; self-directed learners bypass prerequisites
  app.get("/api/class-lessons/:lessonId/prerequisite-status", isAuthenticated, async (req: any, res) => {
    try {
      const userId = getRequestUserId(req);
      const { lessonId } = req.params;
      
      // Get the class lesson
      const lesson = await storage.getClassCurriculumLesson(lessonId);
      if (!lesson) {
        return res.status(404).json({ error: "Lesson not found" });
      }
      
      // If no prerequisite, lesson is unlocked
      if (!lesson.prerequisiteLessonId) {
        return res.json({
          isLocked: false,
          prerequisite: null,
          message: null,
        });
      }
      
      // Get the prerequisite lesson details
      const prerequisiteLesson = await storage.getClassCurriculumLesson(lesson.prerequisiteLessonId);
      if (!prerequisiteLesson) {
        // Prerequisite lesson not found, allow access
        return res.json({
          isLocked: false,
          prerequisite: null,
          message: null,
        });
      }
      
      // Check if prerequisite is a drill lesson
      if (prerequisiteLesson.lessonType === 'drill') {
        // Get the source lesson ID for drill items (drills are stored by curriculum lesson ID)
        const drillLessonId = prerequisiteLesson.sourceLessonId || prerequisiteLesson.id;
        const completion = await storage.checkDrillLessonCompletion(userId, drillLessonId);
        
        if (completion.completed) {
          return res.json({
            isLocked: false,
            prerequisite: {
              id: prerequisiteLesson.id,
              name: prerequisiteLesson.name,
              lessonType: prerequisiteLesson.lessonType,
              completionPercent: completion.completionPercent,
            },
            message: null,
          });
        } else {
          return res.json({
            isLocked: true,
            prerequisite: {
              id: prerequisiteLesson.id,
              name: prerequisiteLesson.name,
              lessonType: prerequisiteLesson.lessonType,
              completionPercent: completion.completionPercent,
              masteredCount: completion.masteredCount,
              totalCount: completion.totalCount,
            },
            message: `Complete "${prerequisiteLesson.name}" first to unlock this lesson`,
          });
        }
      }
      
      // For non-drill prerequisites, check if there's any conversation progress
      // For now, we'll just allow access (conversation completion tracking is more complex)
      return res.json({
        isLocked: false,
        prerequisite: {
          id: prerequisiteLesson.id,
          name: prerequisiteLesson.name,
          lessonType: prerequisiteLesson.lessonType,
        },
        message: null,
      });
      
    } catch (error: any) {
      console.error('Error checking prerequisite status:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // ===== Drill Audio Generation =====

  // Generate audio for all drill items in a lesson (teachers only)
  app.post("/api/drill-audio/generate/:lessonId", mutationLimiter, isAuthenticated, async (req: any, res) => {
    try {
      const userId = getRequestUserId(req);
      const user = await storage.getUser(userId);
      
      if (!hasTeacherAccess(user?.role)) {
        return res.status(403).json({ error: "Only teachers can generate drill audio" });
      }

      const { lessonId } = req.params;
      const { language, speakingRate, forceRegenerate } = req.body;
      
      if (!language) {
        return res.status(400).json({ error: "language is required" });
      }

      // Use tutorGender as unified voice preference (default to female)
      const voiceGender = user?.tutorGender || 'female';

      const { generateAudioForLesson } = await import('./services/drill-audio-service');
      const results = await generateAudioForLesson(
        lessonId,
        language,
        speakingRate || 0.9,
        forceRegenerate || false,
        voiceGender as 'female' | 'male'
      );
      
      res.json({
        message: "Audio generation complete",
        results,
        successCount: results.filter(r => r.audioUrl).length,
        totalCount: results.length,
      });
    } catch (error: any) {
      console.error('Error generating drill audio:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Pre-warm audio cache for drill lessons (generates both slow and normal speeds)
  // This enables instant playback for students during voice sessions
  app.post("/api/admin/drill-audio/prewarm", mutationLimiter, isAuthenticated, async (req: any, res) => {
    try {
      const userId = getRequestUserId(req);
      const user = await storage.getUser(userId);
      
      if (!hasTeacherAccess(user?.role)) {
        return res.status(403).json({ error: "Only teachers can pre-warm audio cache" });
      }

      const { lessonId, lessonIds, language, gender = 'female' } = req.body;
      
      if (!language) {
        return res.status(400).json({ error: "language is required" });
      }
      
      const { preWarmLessonAudioCache, preWarmMultipleLessonsAudioCache } = await import('./services/drill-audio-service');
      
      if (lessonIds && Array.isArray(lessonIds)) {
        // Batch pre-warm multiple lessons
        const result = await preWarmMultipleLessonsAudioCache(lessonIds, language, gender);
        res.json({
          message: "Batch pre-warm complete",
          ...result,
        });
      } else if (lessonId) {
        // Single lesson pre-warm
        const result = await preWarmLessonAudioCache(lessonId, language, gender);
        res.json({
          message: "Pre-warm complete",
          ...result,
        });
      } else {
        return res.status(400).json({ error: "Either lessonId or lessonIds is required" });
      }
    } catch (error: any) {
      console.error('Error pre-warming audio cache:', error);
      res.status(500).json({ error: error.message });
    }
  });

