  // Quick Enroll - streamlined test user setup (admin/developer only)
  app.post("/api/admin/quick-enroll", isAuthenticated, loadAuthenticatedUser(storage), async (req: any, res) => {
    try {
      const adminId = getRequestUserId(req)!;
      
      // Check admin or developer role
      const adminUser = await storage.getUser(adminId);
      if (!adminUser || !hasAdminAccess(adminUser.role)) {
        return res.status(403).json({ error: "Admin or developer access required" });
      }
      
      const { email, firstName, lastName, classId, creditHours, sendEmail = true, enrollInAllPublic = false } = req.body;
      
      // Validate required fields
      if (!email) {
        return res.status(400).json({ error: "Email is required" });
      }
      
      // Check if user already exists
      const existingUser = await storage.getUserByEmail(email.toLowerCase());
      if (existingUser) {
        return res.status(400).json({ error: "A user with this email already exists" });
      }
      
      // Validate classId if provided (only used if not enrolling in all public)
      let teacherClass = null;
      if (classId && !enrollInAllPublic) {
        teacherClass = await storage.getClass(classId);
        if (!teacherClass) {
          return res.status(400).json({ error: "Class not found" });
        }
      }
      
      // Get all public classes if enrollInAllPublic is true
      let publicClasses: any[] = [];
      if (enrollInAllPublic) {
        const allClasses = await getUserDb().select()
          .from(teacherClasses)
          .where(eq(teacherClasses.isPublicCatalogue, true));
        publicClasses = allClasses;
        console.log(`[Quick Enroll] Found ${publicClasses.length} public classes for auto-enrollment`);
      }
      
      // 1. Create user as test account with pending auth
      const newUser = await storage.createUser({
        email: email.toLowerCase(),
        firstName: firstName || null,
        lastName: lastName || null,
        role: 'student',
        authProvider: 'pending',
        isTestAccount: true,
      });
      
      let enrollmentResult = null;
      let enrolledClassCount = 0;
      let creditsGranted = false;
      let emailSent = false;
      let emailError = null;
      
      // 2. Enroll in classes
      if (enrollInAllPublic && publicClasses.length > 0) {
        // Enroll in all public classes
        for (const cls of publicClasses) {
          try {
            await storage.enrollStudent(cls.id, newUser.id);
            enrolledClassCount++;
          } catch (err: any) {
            console.warn(`[Quick Enroll] Failed to enroll in class ${cls.name}: ${err.message}`);
          }
        }
        console.log(`[Quick Enroll] Enrolled ${email} in ${enrolledClassCount}/${publicClasses.length} public classes`);
      } else if (teacherClass) {
        // Enroll in single selected class
        enrollmentResult = await storage.enrollStudent(classId, newUser.id);
        enrolledClassCount = 1;
        console.log(`[Quick Enroll] Enrolled ${email} in class ${teacherClass.name}`);
      }
      
      // 3. Optionally grant credits
      if (creditHours && creditHours > 0) {
        await storage.grantCredits(
          newUser.id,
          creditHours,
          `Quick Enroll: ${creditHours} hours for testing`
        );
        creditsGranted = true;
        console.log(`[Quick Enroll] Granted ${creditHours} hours to ${email}`);
      }
      
      // 4. Sync retired (Jan 2026 - Neon Phase 3)
      // With Neon routing, user data automatically routes to the correct database
      // No cross-environment sync needed - direct database access replaces sync-bridge
      let syncedToProd = false;
      let syncError = 'Sync retired - Neon routing is primary';
      console.log(`[Quick Enroll] Sync skipped (Neon routing handles data routing)`)
      
      // 5. Send invitation email
      if (sendEmail) {
        try {
          const inviteResult = await passwordAuthService.createInvitation({
            email: email.toLowerCase(),
            firstName: firstName || undefined,
            lastName: lastName || undefined,
            role: 'student',
          }, adminId);
          
          if (inviteResult.success && inviteResult.token) {
            await emailService.sendInvitation({
        isBetaTester: newUser.isBetaTester || false,
              to: email.toLowerCase(),
              firstName: firstName || undefined,
              inviterName: adminUser ? `${adminUser.firstName || ''} ${adminUser.lastName || ''}`.trim() || undefined : undefined,
              role: 'student',
              token: inviteResult.token,
            });
            emailSent = true;
            console.log(`[Quick Enroll] Sent invitation email to ${email}`);
          } else {
            emailError = inviteResult.error || "Failed to create invitation token";
            console.error('[Quick Enroll] Invitation creation failed:', emailError);
          }
        } catch (err: any) {
          emailError = err.message || "Email sending failed";
          console.error('[Quick Enroll] Error sending email:', err);
        }
      }
      
      // Log the action
      await storage.logAdminAction({
        actorId: adminId,
        action: 'quick_enroll',
        targetType: 'user',
        targetId: newUser.id,
        metadata: { 
          email, 
          firstName, 
          lastName, 
          classId, 
          creditHours,
          emailSent,
          enrolledClassCount,
          enrollInAllPublic,
          syncedToProd,
        },
        ipAddress: req.ip,
        userAgent: req.get('user-agent'),
      });
      
      // Build enrollment message
      let enrollmentMessage = '';
      if (enrollInAllPublic && enrolledClassCount > 0) {
        enrollmentMessage = ` and enrolled in ${enrolledClassCount} public classes`;
      } else if (enrollmentResult) {
        enrollmentMessage = ' and enrolled in class';
      }
      
      res.status(201).json({
        success: true,
        user: newUser,
        enrollment: enrollmentResult,
        enrolledClassCount,
        creditsGranted,
        emailSent,
        emailError,
        syncedToProd,
        syncError,
        message: `Created test user ${email}${enrollmentMessage}${creditsGranted ? ` with ${creditHours} hours` : ''}${syncedToProd ? ' (synced to prod)' : syncError ? ` (sync failed: ${syncError})` : ''}${emailSent ? ' - invitation sent' : emailError ? ` (email failed: ${emailError})` : ''}`,
      });
    } catch (error: any) {
      console.error('Error in quick enroll:', error);
      res.status(500).json({ error: error.message });
    }
  });

