  // Bulk initialize syllabi for all classes that have curriculum templates but no units
  app.post("/api/admin/classes/initialize-syllabi", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const adminId = req.user?.claims?.sub;
      
      // Get all classes with curriculum templates
      const allClasses = await db
        .select()
        .from(teacherClasses)
        .where(isNotNull(teacherClasses.curriculumPathId));
      
      const results: { classId: string; className: string; status: string; units?: number; lessons?: number }[] = [];
      
      for (const teacherClass of allClasses) {
        // Check if class already has units
        const existingUnits = await storage.getClassCurriculumUnits(teacherClass.id);
        
        if (existingUnits.length > 0) {
          results.push({
            classId: teacherClass.id,
            className: teacherClass.name,
            status: 'skipped_has_syllabus',
            units: existingUnits.length,
          });
          continue;
        }
        
        // Clone curriculum to class
        try {
          const cloned = await storage.cloneCurriculumToClass(teacherClass.id, teacherClass.curriculumPathId!);
          results.push({
            classId: teacherClass.id,
            className: teacherClass.name,
            status: 'initialized',
            units: cloned.units.length,
            lessons: cloned.lessons.length,
          });
        } catch (cloneError: any) {
          results.push({
            classId: teacherClass.id,
            className: teacherClass.name,
            status: 'error',
          });
          console.error(`Error initializing syllabus for class ${teacherClass.name}:`, cloneError);
        }
      }
      
      const initialized = results.filter(r => r.status === 'initialized');
      const skipped = results.filter(r => r.status === 'skipped_has_syllabus');
      const errors = results.filter(r => r.status === 'error');
      
      console.log(`[Bulk Syllabus Init] Initialized: ${initialized.length}, Skipped: ${skipped.length}, Errors: ${errors.length}`);
      
      // Log admin action
      await storage.logAdminAction({
        actorId: adminId,
        action: 'bulk_initialize_syllabi',
        targetType: 'system',
        targetId: 'all_classes',
        metadata: { 
          initialized: initialized.length, 
          skipped: skipped.length, 
          errors: errors.length,
          totalClasses: allClasses.length,
        },
        ipAddress: req.ip,
        userAgent: req.get('user-agent'),
      });
      
      res.json({
        success: true,
        initialized: initialized.length,
        skipped: skipped.length,
        errors: errors.length,
        details: results,
      });
    } catch (error: any) {
      console.error('Error in bulk syllabus initialization:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Link drill lessons as prerequisites for conversation lessons
  app.post("/api/admin/classes/link-prerequisites", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const adminId = req.user?.claims?.sub;
      
      // Get all classes
      const allClasses = await db
        .select()
        .from(teacherClasses);
      
      const linkedPairs: { classId: string; drillLesson: string; conversationLesson: string }[] = [];
      
      for (const teacherClass of allClasses) {
        // Get all class lessons
        const classLessons = await db
          .select({
            id: classCurriculumLessons.id,
            name: classCurriculumLessons.name,
            lessonType: classCurriculumLessons.lessonType,
            unitId: classCurriculumLessons.unitId,
            orderIndex: classCurriculumLessons.orderIndex,
          })
          .from(classCurriculumLessons)
          .innerJoin(classCurriculumUnits, eq(classCurriculumLessons.unitId, classCurriculumUnits.id))
          .where(eq(classCurriculumUnits.classId, teacherClass.id))
          .orderBy(classCurriculumLessons.orderIndex);
        
        const drillLessons = classLessons.filter(l => l.lessonType === 'drill');
        const conversationLessons = classLessons.filter(l => l.lessonType === 'conversation');
        
        // For each drill lesson, find matching conversation lesson in same unit
        for (const drillLesson of drillLessons) {
          const drillTopic = drillLesson.name.toLowerCase()
            .replace(/lesson \d+:\s*/i, '')
            .replace(/ drill$/i, '')
            .trim();
          
          // Find matching conversation lesson
          const matchingConversation = conversationLessons.find(conv => {
            const convTopic = conv.name.toLowerCase()
              .replace(/lesson \d+:\s*/i, '')
              .replace(/ conversation$/i, '')
              .trim();
            return (convTopic === drillTopic || 
                    conv.name.toLowerCase().includes(drillTopic) || 
                    drillLesson.name.toLowerCase().includes(convTopic)) &&
                   conv.unitId === drillLesson.unitId;
          });
          
          if (matchingConversation) {
            await db
              .update(classCurriculumLessons)
              .set({ prerequisiteLessonId: drillLesson.id })
              .where(eq(classCurriculumLessons.id, matchingConversation.id));
            
            linkedPairs.push({
              classId: teacherClass.id,
              drillLesson: drillLesson.name,
              conversationLesson: matchingConversation.name,
            });
          }
        }
      }
      
      console.log(`[Link Prerequisites] Linked ${linkedPairs.length} drill→conversation pairs`);
      
      // Log admin action
      await storage.logAdminAction({
        actorId: adminId,
        action: 'link_drill_prerequisites',
        targetType: 'system',
        targetId: 'all_classes',
        metadata: { linkedPairs: linkedPairs.length },
        ipAddress: req.ip,
        userAgent: req.get('user-agent'),
      });
      
      res.json({
        success: true,
        linkedPairs: linkedPairs.length,
        details: linkedPairs,
      });
    } catch (error: any) {
      console.error('Error linking prerequisites:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // ===== Teaching Tool Analytics (Daniela's Neural Network Visualization) =====
  
  // Get overall teaching tool usage summary
  app.get("/api/admin/teaching-tools/summary", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin', 'developer'), async (req: any, res) => {
    try {
      const { days = '30' } = req.query;
      const daysAgo = new Date();
      daysAgo.setDate(daysAgo.getDate() - parseInt(days as string));
      
      // Get tool usage counts and effectiveness
      const toolStats = await getUserDb().select({
        toolType: teachingToolEvents.toolType,
        count: sql<number>`count(*)`,
        uniqueStudents: sql<number>`count(distinct ${teachingToolEvents.userId})`,
        avgResponseTime: sql<number>`avg(${teachingToolEvents.studentResponseTime})`,
        drillCorrect: sql<number>`sum(case when ${teachingToolEvents.drillResult} = 'correct' then 1 else 0 end)`,
        drillTotal: sql<number>`sum(case when ${teachingToolEvents.drillResult} is not null then 1 else 0 end)`,
      })
        .from(teachingToolEvents)
        .where(gte(teachingToolEvents.occurredAt, daysAgo))
        .groupBy(teachingToolEvents.toolType)
        .orderBy(sql`count(*) desc`);
      
      // Get daily trend
      const dailyTrend = await getUserDb().select({
        date: sql<string>`date(${teachingToolEvents.occurredAt})`,
        count: sql<number>`count(*)`,
      })
        .from(teachingToolEvents)
        .where(gte(teachingToolEvents.occurredAt, daysAgo))
        .groupBy(sql`date(${teachingToolEvents.occurredAt})`)
        .orderBy(sql`date(${teachingToolEvents.occurredAt})`);
      
      // Calculate totals
      const totalEvents = toolStats.reduce((sum, t) => sum + Number(t.count), 0);
      const uniqueStudentIds = new Set<string>();
      
      // Get actual unique students by querying distinct userIds
      const uniqueStudentsResult = await getUserDb().selectDistinct({ userId: teachingToolEvents.userId })
        .from(teachingToolEvents)
        .where(and(
          gte(teachingToolEvents.occurredAt, daysAgo),
          isNotNull(teachingToolEvents.userId)
        ));
      const totalStudents = uniqueStudentsResult.length;
      
      // Calculate overall drill accuracy
      const totalDrillCorrect = toolStats.reduce((sum, t) => sum + Number(t.drillCorrect || 0), 0);
      const totalDrillTotal = toolStats.reduce((sum, t) => sum + Number(t.drillTotal || 0), 0);
      const avgDrillAccuracy = totalDrillTotal > 0 
        ? Math.round((totalDrillCorrect / totalDrillTotal) * 100) 
        : null;
      
      res.json({
        toolStats: toolStats.map(t => ({
          toolType: t.toolType,
          count: Number(t.count),
          uniqueStudents: Number(t.uniqueStudents),
          avgResponseTime: t.avgResponseTime ? Math.round(Number(t.avgResponseTime)) : null,
          drillCorrect: Number(t.drillCorrect || 0),
          drillTotal: Number(t.drillTotal || 0),
        })),
        dailyTrend: dailyTrend.map(d => ({
          date: d.date,
          count: Number(d.count),
        })),
        totals: {
          totalEvents,
          uniqueStudents: totalStudents,
          avgDrillAccuracy,
        },
      });
    } catch (error: any) {
      console.error('Error fetching teaching tool summary:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Get per-student teaching tool effectiveness
  app.get("/api/admin/teaching-tools/by-student", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin', 'developer'), async (req: any, res) => {
    try {
      const { days = '30', limit = '50' } = req.query;
      const daysAgo = new Date();
      daysAgo.setDate(daysAgo.getDate() - parseInt(days as string));
      
      // Get per-student tool usage breakdown
      const studentStats = await getUserDb().select({
        userId: teachingToolEvents.userId,
        language: teachingToolEvents.language,
        toolType: teachingToolEvents.toolType,
        count: sql<number>`count(*)`,
        avgResponseTime: sql<number>`avg(${teachingToolEvents.studentResponseTime})`,
        drillCorrect: sql<number>`sum(case when ${teachingToolEvents.drillResult} = 'correct' then 1 else 0 end)`,
        drillTotal: sql<number>`sum(case when ${teachingToolEvents.drillResult} is not null then 1 else 0 end)`,
      })
        .from(teachingToolEvents)
        .where(and(
          gte(teachingToolEvents.occurredAt, daysAgo),
          isNotNull(teachingToolEvents.userId)
        ))
        .groupBy(teachingToolEvents.userId, teachingToolEvents.language, teachingToolEvents.toolType)
        .orderBy(sql`count(*) desc`)
        .limit(parseInt(limit as string));
      
      // Group by student with proper tools structure
      const studentMap = new Map<string, {
        userId: string;
        languages: Set<string>;
        tools: Record<string, { count: number; avgResponseTime: number | null; drillAccuracy: number | null }>;
        totalEvents: number;
      }>();
      
      for (const stat of studentStats) {
        if (!stat.userId) continue;
        if (!studentMap.has(stat.userId)) {
          studentMap.set(stat.userId, {
            userId: stat.userId,
            languages: new Set(),
            tools: {},
            totalEvents: 0,
          });
        }
        const student = studentMap.get(stat.userId)!;
        if (stat.language) student.languages.add(stat.language);
        
        // Build tools with full structure
        if (!student.tools[stat.toolType]) {
          student.tools[stat.toolType] = { count: 0, avgResponseTime: null, drillAccuracy: null };
        }
        student.tools[stat.toolType].count += Number(stat.count);
        student.tools[stat.toolType].avgResponseTime = stat.avgResponseTime ? Math.round(Number(stat.avgResponseTime)) : null;
        if (stat.drillTotal && Number(stat.drillTotal) > 0) {
          student.tools[stat.toolType].drillAccuracy = Math.round((Number(stat.drillCorrect) / Number(stat.drillTotal)) * 100);
        }
        student.totalEvents += Number(stat.count);
      }
      
      res.json({
        students: Array.from(studentMap.values())
          .sort((a, b) => b.totalEvents - a.totalEvents)
          .map(s => ({
            userId: s.userId,
            totalEvents: s.totalEvents,
            languages: Array.from(s.languages),
            tools: s.tools,
          })),
        periodDays: parseInt(days as string),
      });
    } catch (error: any) {
      console.error('Error fetching per-student teaching tools:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
