  app.get("/api/admin/tts-meta", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const { PERSONALITY_PRESETS, EXPRESSIVENESS_LEVELS, getAllowedEmotions, getDefaultEmotion } = await import('./services/tts-service');
      
      // Build allowed emotions map for each personality at each expressiveness level
      const emotionsMap: Record<string, Record<number, string[]>> = {};
      const personalities = ['warm', 'calm', 'energetic', 'professional'] as const;
      
      for (const personality of personalities) {
        emotionsMap[personality] = {};
        for (let level = 1; level <= 5; level++) {
          emotionsMap[personality][level] = getAllowedEmotions(personality, level);
        }
      }
      
      res.json({
        personalities: PERSONALITY_PRESETS,
        expressivenessLevels: EXPRESSIVENESS_LEVELS,
        emotionsMap,
        getDefaultEmotion: Object.fromEntries(
          personalities.map(p => [p, getDefaultEmotion(p)])
        ),
      });
    } catch (error: any) {
      console.error('Error fetching TTS metadata:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Preview TTS for admin voice testing (unified via /api/admin/voice-audition)
  // Kept as backward-compatible alias
  app.post("/api/admin/tutor-voices/preview", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const { voiceId, text, language, speakingRate, emotion, provider, elStability, elSimilarityBoost, elStyle, elSpeed, nativeLanguage } = req.body;
      
      if (!voiceId || !text) {
        return res.status(400).json({ error: "voiceId and text are required" });
      }
      
      if (provider === 'elevenlabs') {
        const validatedSpeed = elSpeed !== undefined
          ? Math.max(0.5, Math.min(2.0, parseFloat(elSpeed)))
          : 1.0;
        
        const { getElevenLabsStreamingService } = await import('./services/elevenlabs-streaming');
        const elService = getElevenLabsStreamingService();
        const audioBuffer = await elService.synthesizeToBuffer(text, voiceId, {
          languageCode: language || undefined,
          speakingRate: validatedSpeed,
          elStability: elStability ?? 0.5,
          elSimilarityBoost: elSimilarityBoost ?? 0.75,
          elStyle: elStyle ?? 0,
        });
        
        res.set({
          'Content-Type': 'audio/mpeg',
          'Content-Length': audioBuffer.length,
        });
        return res.send(audioBuffer);
      }
      
      if (provider === 'gemini') {
        const { getGeminiLiveTtsService } = await import('./services/gemini-live-tts');
        const geminiLiveTtsService = getGeminiLiveTtsService();
        const audioBuffer = await geminiLiveTtsService.synthesizeToBuffer(text, voiceId || 'Kore', language || undefined, undefined, nativeLanguage || 'english');
        
        res.set({
          'Content-Type': 'audio/wav',
          'Content-Length': audioBuffer.length,
        });
        return res.send(audioBuffer);
      }

      if (provider === 'google') {
        const validatedGoogleRate = speakingRate !== undefined
          ? Math.max(0.25, Math.min(4.0, parseFloat(speakingRate)))
          : 1.0;
        
        const { getTTSService } = await import('./services/tts-service');
        const ttsService = getTTSService();
        const result = await ttsService.streamSynthesizeToWavBuffer({
          text,
          voiceId,
          speakingRate: validatedGoogleRate,
        });
        
        res.set({
          'Content-Type': result.contentType,
          'Content-Length': result.audioBuffer.length,
        });
        return res.send(result.audioBuffer);
      }
      
      // Use TTS service with configurable speaking rate (Cartesia)
      // Validate speakingRate (0.7 to 1.3 range), default to 0.9
      const validatedRate = speakingRate !== undefined
        ? Math.max(0.7, Math.min(1.3, parseFloat(speakingRate)))
        : 0.9;
      
      const { getTTSService } = await import('./services/tts-service');
      const ttsService = getTTSService();
      const result = await ttsService.synthesize({
        text,
        voiceId,
        language: language || 'en',
        targetLanguage: language || 'en',
        emotion: emotion || 'friendly',
        speakingRate: validatedRate,
      });
      
      res.set({
        'Content-Type': result.contentType,
        'Content-Length': result.audioBuffer.length,
      });
      res.send(result.audioBuffer);
    } catch (error: any) {
      console.error('Error previewing voice:', error);
      res.status(500).json({ error: error.message });
    }
  });

