  // Admin: Backfill conversation titles for untitled conversations
  // Run once to generate titles for existing voice chats that never got titles
  app.post("/api/admin/backfill-conversation-titles", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const limit = parseInt(req.query.limit as string) || 50;
      const dryRun = req.query.dryRun === 'true';
      
      console.log(`[BACKFILL] Starting conversation title backfill (limit: ${limit}, dryRun: ${dryRun})`);
      
      // Find conversations without titles that have at least 4 messages
      const untitledConversations = await getSharedDb()
        .select({
          id: conversations.id,
          userId: conversations.userId,
          language: conversations.language,
          messageCount: conversations.messageCount,
        })
        .from(conversations)
        .where(sql`${conversations.title} IS NULL AND ${conversations.messageCount} >= 4 AND ${conversations.isOnboarding} = false`)
        .orderBy(sql`${conversations.createdAt} DESC`)
        .limit(limit);
      
      console.log(`[BACKFILL] Found ${untitledConversations.length} untitled conversations`);
      
      const results: Array<{ id: number; title: string | null; error?: string }> = [];
      
      for (const conv of untitledConversations) {
        try {
          const messages = await storage.getMessagesByConversation(conv.id);
          
          if (messages.length < 4) {
            results.push({ id: conv.id, title: null, error: 'Not enough messages' });
            continue;
          }
          
          if (dryRun) {
            results.push({ id: conv.id, title: '[DRY RUN - would generate]' });
            continue;
          }
          
          const generatedTitle = await generateConversationTitle(
            messages.map(m => ({ role: m.role, content: m.content })),
            conv.language
          );
          
          if (generatedTitle) {
            await storage.updateConversation(conv.id, conv.userId, { title: generatedTitle });
            console.log(`[BACKFILL] ✓ Generated title for #${conv.id}: "${generatedTitle}"`);
            results.push({ id: conv.id, title: generatedTitle });
          } else {
            results.push({ id: conv.id, title: null, error: 'Title generation returned null' });
          }
          
          // Small delay to avoid rate limiting
          await new Promise(resolve => setTimeout(resolve, 500));
        } catch (err: any) {
          console.warn(`[BACKFILL] Failed for #${conv.id}:`, err.message);
          results.push({ id: conv.id, title: null, error: err.message });
        }
      }
      
      const successCount = results.filter(r => r.title && !r.error).length;
      
      res.json({
        total: untitledConversations.length,
        processed: results.length,
        success: successCount,
        dryRun,
        results,
      });
    } catch (error: any) {
      console.error('[BACKFILL] Error backfilling conversation titles:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // ============================================================================
  // SUPPORT AGENT API ROUTES (Tri-Lane Hive)
  // Voice + Text based support for live handoffs and offline drills
  // ============================================================================
  
  // Helper function for simple support replies (placeholder until AI integration)
  function getSimpleSupportReply(message: string, category: string): string {
    const lowerMessage = message.toLowerCase();
    
    if (lowerMessage.includes('audio') || lowerMessage.includes('sound') || lowerMessage.includes('mic')) {
      return "I understand you're having audio issues. Let's troubleshoot: 1) Check your browser permissions for microphone access. 2) Make sure your device volume isn't muted. 3) Try refreshing the page. Would any of these help, or is the issue something else?";
    }
    
    if (lowerMessage.includes('billing') || lowerMessage.includes('charge') || lowerMessage.includes('payment')) {
      return "I see this is about billing. For security, billing changes need to go through our team. I've noted your concern. Can you tell me more about what you're seeing?";
    }
    
    if (lowerMessage.includes('cancel') || lowerMessage.includes('subscription')) {
      return "I understand you have questions about your subscription. I can help with general info, but changes need to be made in your account settings. Would you like me to explain how to access that?";
    }
    
    if (lowerMessage.includes('slow') || lowerMessage.includes('loading') || lowerMessage.includes('freeze')) {
      return "Performance issues can be frustrating. A few things that often help: 1) Clear your browser cache. 2) Try a different browser. 3) Check your internet connection. If the problem persists, I'll escalate this to our tech team.";
    }
    
    if (lowerMessage.includes('thank')) {
      return "You're welcome! Is there anything else I can help you with today?";
    }
    
    return "I've received your message and I'm looking into it. To help you better, could you provide a bit more detail about what you're experiencing?";
  }

  // Send a text message to Support Agent
  app.post("/api/support/message", isAuthenticated, loadAuthenticatedUser(storage), async (req: any, res) => {
    try {
      const userId = getRequestUserId(req);
      const { ticketId, message, category, mode, drillContext, clientTelemetry } = req.body;
      
      if (!message || typeof message !== 'string') {
        return res.status(400).json({ error: 'Message is required' });
      }
      
      // TEMPORARY: Disable drill mode until proper drill session system is implemented
      // This prevents unauthenticated message submissions via drill-mode path
      if (mode === 'drill') {
        return res.status(501).json({ 
          error: 'Drill mode text is not yet available. Please use the standard drill exercises.',
          code: 'DRILL_MODE_DISABLED'
        });
      }
      
      // Require ticketId for support mode
      if (!ticketId) {
        return res.status(400).json({ error: 'Ticket ID is required' });
      }
      
      // Verify ticket ownership
      const ticket = await storage.getSupportTicket(ticketId);
      if (!ticket) {
        return res.status(404).json({ error: 'Ticket not found' });
      }
      // Only the ticket owner, admin, or support_agent can add messages
      if (ticket.userId !== userId) {
        const user = await storage.getUser(userId);
        if (!user || (user.role !== 'admin' && user.role !== 'super_admin' && user.role !== 'support_agent')) {
          return res.status(403).json({ error: 'Not authorized to message this ticket' });
        }
      }
      
      // Store the user message using storage (reliable persistence)
      await storage.addSupportMessage({
        ticketId,
        senderType: 'user',
        senderId: userId,
        content: message,
      });
      
      // Get AI-powered support reply from Sofia
      const user = await storage.getUser(userId);
      
      // Detect dev mode - developers, admins, founder, and support agents get technical support
      const devRoles = ['developer', 'admin', 'super_admin', 'founder', 'support_agent'];
      const isDevUser = (user?.role && devRoles.includes(user.role)) ||
        user?.email === (process.env.FOUNDER_EMAIL || 'davidwmcintosh@gmail.com');
      const supportMode = isDevUser ? 'dev' : 'user';
      
      // Voice diagnostics for ALL users — Sofia uses them internally for smart diagnosis
      const voiceDiagnosticsContext = voiceDiagnostics.getSupportDiagnostics();
      
      const result = await supportPersonaService.generateResponse({
        ticketId,
        userMessage: message,
        userName: user?.firstName || undefined,
        deviceInfo: ticket.deviceInfo as { browser?: string; os?: string; device?: string } | undefined,
        handoffContext: ticket.handoffReason ? {
          fromDaniela: ticket.handoffReason.includes('Daniela'),
          learningTopic: ticket.handoffReason,
        } : undefined,
        mode: supportMode,
        voiceDiagnostics: voiceDiagnosticsContext,
        clientTelemetry,
      });
      
      // Store the support response using storage (reliable persistence)
      await storage.addSupportMessage({
        ticketId,
        senderType: 'support',
        content: result.response,
      });
      
      res.json({ 
        reply: result.response,
        shouldReturnToDaniela: result.shouldReturnToDaniela,
        knowledgeUsed: result.knowledgeUsed,
      });
    } catch (error: any) {
      console.error('[API] Error handling support message:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
