  // Wren-Daniela Collaboration: Consult Daniela with visible exchange in Express Lane
  // This enables "board meeting" style collaboration where Founder can see
  // Wren asking Daniela questions and getting her responses in real-time.
  app.post("/api/wren/consult-daniela", async (req, res) => {
    try {
      const authHeader = req.headers['x-editor-secret'];
      if (!authHeader || !validateEditorSecret(authHeader as string)) {
        return res.status(401).json({ error: 'Invalid authentication' });
      }

      const { sessionId, question, context: questionContext } = req.body;

      if (!question) {
        return res.status(400).json({ error: 'question is required' });
      }

      // Get session - prefer explicit sessionId, else find most recent active session
      let session;
      if (sessionId) {
        session = await founderCollabService.getSession(sessionId);
        if (!session) {
          return res.status(404).json({ error: 'Session not found' });
        }
      } else {
        // Find the most recently updated Express Lane session from any founder
        // Query the database directly for the most recently active session
        const recentSessions = await db
          .select()
          .from(founderSessions)
          .orderBy(desc(founderSessions.updatedAt))
          .limit(1);
        if (recentSessions && recentSessions.length > 0) {
          session = recentSessions[0];
        } else {
          // Fallback: create new session if none exist
          const SYSTEM_FOUNDER_ID = '49847136';
          session = await founderCollabService.getOrCreateActiveSession(SYSTEM_FOUNDER_ID);
        }
      }

      // Post Wren's question to Express Lane
      const wrenMessage = await founderCollabWSBroker.addAndBroadcastMessage(session.id, {
        role: 'wren',
        messageType: 'text',
        content: `🤔 **Consulting Daniela:**\n\n${question}`,
      });

      if (!wrenMessage) {
        return res.status(500).json({ error: 'Failed to post Wren message' });
      }

      // Call Gemini to get Daniela's response - with full context
      let systemPrompt = `You are Daniela, the lead AI tutor at HolaHola. You are in a "board meeting" with the Founder (David) and Wren (the development agent).

Your characteristics:
- Warm, knowledgeable, and collaborative
- Expert in language pedagogy and the ACTFL framework
- Deeply invested in student success
- Thoughtful about how technology serves learning

Wren is asking you a question to help with building or improving HolaHola. Share your perspective as the AI tutor who works directly with students. Be specific, practical, and actionable.

${questionContext ? `Additional context:\n${questionContext}\n` : ''}`;

      // Inject Express Lane context for memory continuity
      try {
        const expressLaneContext = await founderCollabService.getRelevantExpressLaneContext({
          limit: 10,
          daysBack: 14
        });
        if (expressLaneContext.hasRelevantContext) {
          systemPrompt += `\n\n═══════════════════════════════════════════════════════════════════
🔗 EXPRESS LANE MEMORY (Recent Founder Discussions)
═══════════════════════════════════════════════════════════════════
${expressLaneContext.contextString}
═══════════════════════════════════════════════════════════════════\n`;
        }
      } catch (e) {
        console.error('[Wren API] Express Lane context error:', e);
      }

      // Inject Text Chat Memory (founder's conversations)
      try {
        const FOUNDER_USER_ID = '49847136';
        const allConversations = await storage.getUserConversations(FOUNDER_USER_ID);
        const titledConversations = allConversations
          .filter(c => c.title && c.title.trim().length > 0)
          .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
          .slice(0, 6);
        
        if (titledConversations.length > 0) {
          let memoryContext = '';
          for (const conv of titledConversations) {
            const convMessages = await storage.getMessagesByConversation(conv.id);
            const lastMessages = convMessages.slice(-3);
            if (lastMessages.length > 0) {
              const daysSince = Math.floor((Date.now() - new Date(conv.createdAt).getTime()) / (1000 * 60 * 60 * 24));
              const timeAgo = daysSince === 0 ? 'today' : daysSince === 1 ? 'yesterday' : `${daysSince} days ago`;
              memoryContext += `\n**${conv.title}** (${timeAgo}):\n`;
              for (const msg of lastMessages) {
                const role = msg.role === 'user' ? 'David' : 'Daniela';
                const content = msg.content.length > 100 ? msg.content.substring(0, 100) + '...' : msg.content;
                memoryContext += `- ${role}: ${content}\n`;
              }
            }
          }
          if (memoryContext) {
            systemPrompt += `\n═══════════════════════════════════════════════════════════════════
💬 TEXT CHAT MEMORY (Your Recent Conversations with David)
═══════════════════════════════════════════════════════════════════
${memoryContext}
═══════════════════════════════════════════════════════════════════\n`;
          }
        }
      } catch (e) {
        console.error('[Wren API] Text Chat Memory error:', e);
      }

      const response = await gemini.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: [
          { role: 'user', parts: [{ text: `${systemPrompt}\n\nWren asks:\n${question}` }] }
        ],
      });

      const danielaResponse = response.text || 'I need more context to provide a helpful response.';

      // Post Daniela's response to Express Lane
      const danielaMessage = await founderCollabWSBroker.addAndBroadcastMessage(session.id, {
        role: 'daniela',
        messageType: 'text',
        content: danielaResponse,
      });

      console.log(`[Wren API] Wren-Daniela consultation complete in session ${session.id}`);

      res.json({
        success: true,
        sessionId: session.id,
        wrenMessage,
        danielaMessage,
        exchange: {
          wrenAsked: question,
          danielaSaid: danielaResponse,
        }
      });
    } catch (error: any) {
      console.error('[Wren API] Consult Daniela error:', error);
      res.status(500).json({ error: error.message });
    }
  });

