  // Run Neon migration (Admin/Founder only)
  app.post("/api/admin/neon/migrate", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const { isNeonConfigured, testNeonConnection } = await import('./neon-db');
      
      if (!isNeonConfigured()) {
        return res.status(400).json({ 
          error: 'Neon not configured', 
          message: 'Set DATABASE_URL secret' 
        });
      }
      
      // Test connections first
      const connectionTest = await testNeonConnection();
      if (!connectionTest.shared.success || !connectionTest.user.success) {
        return res.status(500).json({ 
          error: 'Neon connection failed',
          details: connectionTest 
        });
      }
      
      // Import and run migration
      console.log('[NEON-MIGRATE] Starting migration from admin endpoint...');
      const startTime = Date.now();
      const { runMigration } = await import('../scripts/neon-data-migration');
      const result = await runMigration();
      const duration = Date.now() - startTime;
      
      // Calculate totals for UI
      const totalRecords = (result.shared?.rows || 0) + (result.user?.rows || 0);
      const totalTables = (result.shared?.success || 0) + (result.user?.success || 0);
      const failedTables = (result.shared?.failed || 0) + (result.user?.failed || 0);
      
      console.log('[NEON-MIGRATE] Migration complete:', result);
      res.json({ 
        success: true, 
        totalRecords,
        totalTables,
        failedTables,
        duration,
        sharedTables: result.shared,
        userTables: result.user,
        retired: result.retired
      });
    } catch (error: any) {
      console.error('[NEON-MIGRATE] Migration error:', error);
      res.status(500).json({ error: error.message, stack: error.stack });
    }
  });
  
  // Check Neon status (Admin/Founder only)
  app.get("/api/admin/neon/status", isAuthenticated, loadAuthenticatedUser(storage), requireRole('admin'), async (req: any, res) => {
    try {
      const { isNeonConfigured, testNeonConnection } = await import('./neon-db');
      
      const neonConfigured = isNeonConfigured();
      let sharedConnected = false;
      let userConnected = false;
      let sharedUrl: string | null = null;
      let userUrl: string | null = null;
      
      if (neonConfigured) {
        const connectionStatus = await testNeonConnection();
        sharedConnected = connectionStatus.shared.success;
        userConnected = connectionStatus.user.success;
        // Mask URLs for security (show host only)
        if (process.env.DATABASE_URL) {
          try {
            const url = new URL(process.env.DATABASE_URL);
            sharedUrl = url.host;
            userUrl = url.host; // Same database now
          } catch { 
            sharedUrl = "configured"; 
            userUrl = "configured";
          }
        }
      }
      
      res.json({ 
        neonConfigured, 
        sharedConnected,
        userConnected,
        sharedUrl,
        userUrl,
        error: null
      });
    } catch (error: any) {
      console.error('[NEON] Status check error:', error);
      res.status(500).json({ 
        neonConfigured: false,
        sharedConnected: false,
        userConnected: false,
        sharedUrl: null,
        userUrl: null,
        error: error.message 
      });
    }
  });

